// Parse Garmin response and extract relevant fields
// Adjust field names based on actual Garmin Connect API response
const data = $input.first().json;

// This is a template - actual field paths depend on Garmin endpoint used
return [{
  json: {
    calendar_date: new Date().toISOString().split('T')[0],
    sleep_score: data.dailySleepDTO?.sleepScores?.overall?.value ?? null,
    body_battery_max: data.bodyBatteryFeedbackList?.[0]?.bodyBatteryLevel ?? null,
    resting_hr: data.restingHeartRate ?? null,
    hrv_status: data.hrvSummary?.weeklyAvg ? 'balanced' : null,
    hrv_weekly_avg: data.hrvSummary?.weeklyAvg ?? null,
    stress_avg: data.averageStressLevel ?? null,
    raw: data
  }
}];
